import { api } from './client'

export type PaymentStatus = 'pending' | 'paid' | 'overdue' | 'refunded' | 'cancelled'
export type PaymentMethod = 'card' | 'invoice' | 'cash' | 'manual'

export interface PaymentDto {
  id: string
  subscriptionId: string | null
  studentId: string
  amount: string
  currency: string
  status: PaymentStatus
  method: PaymentMethod
  paidAt: string | null
  invoiceUrl: string | null
  notes: string | null
  createdAt: string
  updatedAt: string
}

export interface PaymentFilters {
  studentId?: string
  status?: PaymentStatus
  from?: string
  to?: string
}

export interface CreatePaymentPayload {
  studentId: string
  amount: number | string
  subscriptionId?: string
  currency?: string
  status?: PaymentStatus
  method?: PaymentMethod
  invoiceUrl?: string
  notes?: string
}

export function fetchPayments(filters: PaymentFilters = {}): Promise<PaymentDto[]> {
  const qs = new URLSearchParams()
  if (filters.studentId) qs.set('studentId', filters.studentId)
  if (filters.status) qs.set('status', filters.status)
  if (filters.from) qs.set('from', filters.from)
  if (filters.to) qs.set('to', filters.to)
  const tail = qs.toString() ? `?${qs.toString()}` : ''
  return api.get<PaymentDto[]>(`/payments${tail}`)
}

export function fetchOverduePayments(): Promise<PaymentDto[]> {
  return api.get<PaymentDto[]>('/payments/overdue')
}

export function fetchPaymentsByStudent(studentId: string): Promise<PaymentDto[]> {
  return api.get<PaymentDto[]>(`/payments/student/${studentId}`)
}

export function createPayment(payload: CreatePaymentPayload): Promise<PaymentDto> {
  return api.post<PaymentDto>('/payments', payload)
}

export function markPaymentPaid(id: string): Promise<PaymentDto> {
  return api.patch<PaymentDto>(`/payments/${id}/mark-paid`)
}

export function markPaymentRefunded(id: string): Promise<PaymentDto> {
  return api.patch<PaymentDto>(`/payments/${id}/mark-refunded`)
}

