/**
 * AdminPayments — финансовая таблица: фильтры по статусу/ученику/датам,
 * быстрые действия «Отметить оплачено» и «Возврат».
 */

import { useEffect, useMemo, useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import {
  fetchPayments,
  markPaymentPaid,
  markPaymentRefunded,
  PAYMENT_METHOD_LABELS,
  PAYMENT_STATUS_LABELS,
  type PaymentDto,
  type PaymentStatus,
} from '../api/payments'

const STATUS_COLOR: Record<PaymentStatus, string> = {
  pending: '#FFD43C',
  paid: '#9FE8C7',
  overdue: '#FFB4C8',
  refunded: '#A9D8FF',
  cancelled: '#cccccc',
}

const STATUS_OPTIONS: Array<{ value: '' | PaymentStatus; label: string }> = [
  { value: '', label: 'Все статусы' },
  { value: 'pending', label: 'Ожидают' },
  { value: 'paid', label: 'Оплачены' },
  { value: 'overdue', label: 'Просрочены' },
  { value: 'refunded', label: 'Возвращены' },
  { value: 'cancelled', label: 'Отменены' },
]

function fmtMoney(amount: string, currency: string): string {
  const n = Number(amount)
  if (Number.isNaN(n)) return `${amount} ${currency}`
  return `${n.toLocaleString('ru-RU')} ${currency}`
}

export default function AdminPayments() {
  const { toast, show } = useToast()

  const [rows, setRows] = useState<PaymentDto[]>([])
  const [loading, setLoading] = useState(true)
  const [busyId, setBusyId] = useState<string | null>(null)

  const [statusFilter, setStatusFilter] = useState<'' | PaymentStatus>('')
  const [studentFilter, setStudentFilter] = useState('')
  const [fromFilter, setFromFilter] = useState('')
  const [toFilter, setToFilter] = useState('')

  function load() {
    setLoading(true)
    const filters: Parameters<typeof fetchPayments>[0] = {}
    if (statusFilter) filters.status = statusFilter
    if (studentFilter.trim()) filters.studentId = studentFilter.trim()
    if (fromFilter) filters.from = fromFilter
    if (toFilter) filters.to = toFilter
    fetchPayments(filters)
      .then(setRows)
      .catch(() => show('Ошибка загрузки платежей', 'error'))
      .finally(() => setLoading(false))
  }

  useEffect(load, [statusFilter])

  const totals = useMemo(() => {
    const sumPaid = rows.filter((r) => r.status === 'paid').reduce((acc, r) => acc + Number(r.amount), 0)
    const sumOverdue = rows.filter((r) => r.status === 'overdue').reduce((acc, r) => acc + Number(r.amount), 0)
    const sumPending = rows.filter((r) => r.status === 'pending').reduce((acc, r) => acc + Number(r.amount), 0)
    return { sumPaid, sumOverdue, sumPending }
  }, [rows])

  async function handleMarkPaid(id: string) {
    setBusyId(id)
    try {
      await markPaymentPaid(id)
      show('Отмечено как оплаченное', 'success')
      load()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setBusyId(null)
    }
  }

  async function handleRefund(id: string) {
    setBusyId(id)
    try {
      await markPaymentRefunded(id)
      show('Возврат оформлен', 'success')
      load()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setBusyId(null)
    }
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>💳</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Финансы</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Платежи</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1400, margin: '0 auto', padding: '20px 16px' }}>
        {/* Totals */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 12, marginBottom: 16 }}>
          <div className="kb-card" style={{ padding: 14 }}>
            <div style={{ fontSize: 11, color: 'var(--ink-soft)' }}>Оплачено</div>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#059669' }}>{totals.sumPaid.toLocaleString('ru-RU')} ₽</div>
          </div>
          <div className="kb-card" style={{ padding: 14 }}>
            <div style={{ fontSize: 11, color: 'var(--ink-soft)' }}>Ожидает оплаты</div>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#b78103' }}>{totals.sumPending.toLocaleString('ru-RU')} ₽</div>
          </div>
          <div className="kb-card" style={{ padding: 14 }}>
            <div style={{ fontSize: 11, color: 'var(--ink-soft)' }}>Просрочено</div>
            <div style={{ fontSize: 22, fontWeight: 800, color: '#dc2626' }}>{totals.sumOverdue.toLocaleString('ru-RU')} ₽</div>
          </div>
          <div className="kb-card" style={{ padding: 14 }}>
            <div style={{ fontSize: 11, color: 'var(--ink-soft)' }}>Записей</div>
            <div style={{ fontSize: 22, fontWeight: 800 }}>{rows.length}</div>
          </div>
        </div>

        {/* Filters */}
        <div className="kb-card" style={{ padding: 14, marginBottom: 16, display: 'flex', flexWrap: 'wrap', gap: 8, alignItems: 'flex-end' }}>
          <label style={{ display: 'flex', flexDirection: 'column', gap: 4, fontSize: 12 }}>
            Статус
            <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value as '' | PaymentStatus)} style={{ padding: 8, borderRadius: 8 }}>
              {STATUS_OPTIONS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
            </select>
          </label>
          <label style={{ display: 'flex', flexDirection: 'column', gap: 4, fontSize: 12 }}>
            Student ID
            <input value={studentFilter} onChange={(e) => setStudentFilter(e.target.value)} placeholder="UUID ученика" style={{ padding: 8, borderRadius: 8, fontFamily: 'monospace', fontSize: 12, minWidth: 280 }} />
          </label>
          <label style={{ display: 'flex', flexDirection: 'column', gap: 4, fontSize: 12 }}>
            С
            <input type="date" value={fromFilter} onChange={(e) => setFromFilter(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
          </label>
          <label style={{ display: 'flex', flexDirection: 'column', gap: 4, fontSize: 12 }}>
            По
            <input type="date" value={toFilter} onChange={(e) => setToFilter(e.target.value)} style={{ padding: 8, borderRadius: 8 }} />
          </label>
          <button className="kb-btn" onClick={load} style={{ background: 'var(--violet)', color: '#fff' }}>Применить</button>
          <button className="kb-btn" onClick={() => { setStatusFilter(''); setStudentFilter(''); setFromFilter(''); setToFilter('') }}>Сбросить</button>
        </div>

        {/* Table */}
        {loading ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
        ) : rows.length === 0 ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Нет платежей по выбранным фильтрам.</div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13, minWidth: 900 }}>
              <thead>
                <tr style={{ background: 'var(--paper-2, #f9f8ff)' }}>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Дата</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Ученик</th>
                  <th style={{ padding: 10, textAlign: 'right', fontWeight: 700 }}>Сумма</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Метод</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Статус</th>
                  <th style={{ padding: 10, textAlign: 'left', fontWeight: 700 }}>Действия</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((p) => (
                  <tr key={p.id} style={{ borderTop: '1px solid var(--paper-3, #e5e2f0)' }}>
                    <td style={{ padding: 10, whiteSpace: 'nowrap' }}>
                      {new Date(p.createdAt).toLocaleString('ru-RU', { day: '2-digit', month: '2-digit', year: 'numeric' })}
                    </td>
                    <td style={{ padding: 10, fontFamily: 'monospace', fontSize: 11 }}>{p.studentId.slice(0, 8)}…</td>
                    <td style={{ padding: 10, textAlign: 'right', fontWeight: 700 }}>{fmtMoney(p.amount, p.currency)}</td>
                    <td style={{ padding: 10 }}>{PAYMENT_METHOD_LABELS[p.method]}</td>
                    <td style={{ padding: 10 }}>
                      <span style={{ background: STATUS_COLOR[p.status], padding: '3px 8px', borderRadius: 6, fontSize: 12, fontWeight: 700 }}>
                        {PAYMENT_STATUS_LABELS[p.status]}
                      </span>
                    </td>
                    <td style={{ padding: 10, display: 'flex', gap: 6 }}>
                      {(p.status === 'pending' || p.status === 'overdue') && (
                        <button className="kb-btn" disabled={busyId === p.id} onClick={() => void handleMarkPaid(p.id)} style={{ background: '#059669', color: '#fff', fontSize: 12, padding: '6px 10px' }}>
                          Отметить оплачено
                        </button>
                      )}
                      {p.status === 'paid' && (
                        <button className="kb-btn" disabled={busyId === p.id} onClick={() => void handleRefund(p.id)} style={{ background: '#dc2626', color: '#fff', fontSize: 12, padding: '6px 10px' }}>
                          Возврат
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </PlatformShell>
  )
}
